/**
 * Notification log model — types for tracking notification delivery history.
 *
 * Architecture: The NotificationHistoryService listens for notification lifecycle
 * events (notification:sent, notification:failed) on the EventBus and persists
 * a NotificationLogEntry for each via the NotificationLogRepository.
 *
 * This provides a durable, queryable audit trail of all notification activity,
 * separate from the in-memory records held by NotificationService.
 *
 * Fields captured per entry:
 * - recipient: Who the notification was sent to
 * - channel: The delivery channel used (email, sms, webhook, in_app)
 * - type: The notification type (order_confirmation, welcome, etc.)
 * - timestamp: When the log entry was recorded
 * - deliveryStatus: Whether delivery succeeded or failed
 * - notificationId: Link back to the original NotificationRecord ID
 * - subject/body: Content that was sent
 * - failureReason: If delivery failed, why
 * - metadata: Any additional context carried from the notification
 */

import type {
  NotificationType,
  NotificationChannel,
  NotificationPriority,
} from './notification.js';

/**
 * Delivery status for a logged notification.
 */
export type DeliveryStatus = 'sent' | 'failed';

/**
 * A persisted log entry for a notification that was dispatched.
 * Created by the NotificationHistoryService when it observes
 * notification:sent or notification:failed events.
 */
export interface NotificationLogEntry {
  /** Unique log entry ID (e.g., nlog-0001). */
  id: string;
  /** The original NotificationRecord ID this log entry corresponds to. */
  notificationId: string;
  /** The notification type. */
  type: NotificationType;
  /** The delivery channel used. */
  channel: NotificationChannel;
  /** Recipient identifier (email, user ID, webhook URL, etc.). */
  recipient: string;
  /** Subject line of the notification. */
  subject: string;
  /** Body content of the notification. */
  body: string;
  /** Delivery priority. */
  priority: NotificationPriority;
  /** Whether delivery succeeded or failed. */
  deliveryStatus: DeliveryStatus;
  /** When the log entry was recorded. */
  timestamp: Date;
  /** Reason for failure (if deliveryStatus is 'failed'). */
  failureReason?: string;
  /** Optional metadata carried from the notification. */
  metadata?: Record<string, unknown>;
}

/**
 * Query options for filtering notification history.
 * All fields are optional; omit a field to skip that filter.
 */
export interface NotificationHistoryQuery {
  /** Filter by recipient identifier. */
  recipient?: string;
  /** Filter by notification type. */
  type?: NotificationType;
  /** Filter by delivery channel. */
  channel?: NotificationChannel;
  /** Filter by delivery status. */
  deliveryStatus?: DeliveryStatus;
  /** Include only entries on or after this date. */
  startDate?: Date;
  /** Include only entries on or before this date. */
  endDate?: Date;
}

/**
 * Repository for NotificationLogEntry data access.
 *
 * Extends BaseRepository with notification-log-specific query methods
 * for filtering by recipient, type, channel, and date range.
 *
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  NotificationLogEntry,
  DeliveryStatus,
} from '../models/notification-log.js';
import type {
  NotificationType,
  NotificationChannel,
} from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      type: record['type'] as NotificationType,
      channel: record['channel'] as NotificationChannel,
      recipient: record['recipient'] as string,
      subject: record['subject'] as string,
      body: record['body'] as string,
      priority: record['priority'] as NotificationLogEntry['priority'],
      deliveryStatus: record['deliveryStatus'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
    };

    if (record['failureReason'] !== undefined) {
      entry.failureReason = record['failureReason'] as string;
    }

    if (record['metadata'] !== undefined) {
      entry.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }

    return entry;
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      type: entity.type,
      channel: entity.channel,
      recipient: entity.recipient,
      subject: entity.subject,
      body: entity.body,
      priority: entity.priority,
      deliveryStatus: entity.deliveryStatus,
      timestamp: entity.timestamp.toISOString(),
    };

    if (entity.failureReason !== undefined) {
      record['failureReason'] = entity.failureReason;
    }

    if (entity.metadata !== undefined) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }

    return record;
  }

  /**
   * Find all log entries for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.recipient === recipient);
  }

  /**
   * Find all log entries of a specific notification type.
   */
  findByType(type: NotificationType): NotificationLogEntry[] {
    return this.findAll((entry) => entry.type === type);
  }

  /**
   * Find all log entries for a specific delivery channel.
   */
  findByChannel(channel: NotificationChannel): NotificationLogEntry[] {
    return this.findAll((entry) => entry.channel === channel);
  }

  /**
   * Find all log entries with a specific delivery status.
   */
  findByDeliveryStatus(status: DeliveryStatus): NotificationLogEntry[] {
    return this.findAll((entry) => entry.deliveryStatus === status);
  }

  /**
   * Find all log entries within a date range (inclusive).
   */
  findByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.findAll(
      (entry) => entry.timestamp >= startDate && entry.timestamp <= endDate,
    );
  }

  /**
   * Find the log entry for a specific notification ID.
   */
  findByNotificationId(notificationId: string): NotificationLogEntry | undefined {
    const results = this.findAll((entry) => entry.notificationId === notificationId);
    return results[0];
  }
}

/**
 * Notification history service — persists and queries notification delivery history.
 *
 * ARCHITECTURE DECISION: Event-Driven Log Capture
 * ================================================
 * This service integrates with the existing notification flow by subscribing
 * to notification lifecycle events on the EventBus:
 * - notification:sent  → logs a successful delivery
 * - notification:failed → logs a failed delivery
 *
 * It does NOT intercept or modify the notification dispatch path. Instead it
 * passively observes the events that the NotificationService already emits,
 * making it fully decoupled and backwards-compatible.
 *
 * The logged entries are persisted through the NotificationLogRepository
 * (Repository pattern), providing a durable, queryable audit trail.
 *
 * Query capabilities:
 * - By recipient (who received the notification)
 * - By notification type (order_confirmation, welcome, etc.)
 * - By delivery channel (email, sms, webhook, in_app)
 * - By delivery status (sent, failed)
 * - By date range (start/end timestamps)
 * - Combined filtering via NotificationHistoryQuery
 * - Paginated results via the paginate() utility
 *
 * Depends on:
 * - EventBus (event system) for receiving notification lifecycle events
 * - NotificationLogRepository (data layer) for persistence
 *
 * CONSTRAINTS:
 * - All event subscriptions go through EventBus.on() (no CallbackRegistry).
 * - This service is read-heavy; writes only happen in response to events.
 * - Does NOT depend on NotificationService directly (loose coupling via events).
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  NotificationSentEvent,
  NotificationFailedEvent,
} from '../events/event-types.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type {
  NotificationLogEntry,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { paginate } from '../utils/pagination.js';
import type { PaginationResult } from '../utils/pagination.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Used in tests. */
export function resetNotificationLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private eventBus: EventBus,
    private logRepository: NotificationLogRepository,
  ) {
    this.registerEventHandlers();
  }

  // ---------------------------------------------------------------------------
  // Event Handlers — Capture notification lifecycle events
  // ---------------------------------------------------------------------------

  /**
   * Register event handlers for notification lifecycle events.
   *
   * IMPORTANT: ALL event subscriptions go through EventBus.on().
   * Do NOT use CallbackRegistry or direct callbacks.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.handleNotificationSent(event);
    });

    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.handleNotificationFailed(event);
    });
  }

  /**
   * Handle a successful notification delivery — log it as 'sent'.
   */
  private handleNotificationSent(event: NotificationSentEvent): void {
    const { notification } = event;
    this.logger.info(
      `Logging sent notification: ${notification.id} to ${notification.recipient}`,
    );

    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: notification.id,
      type: notification.type,
      channel: notification.channel,
      recipient: notification.recipient,
      subject: notification.subject,
      body: notification.body,
      priority: notification.priority,
      deliveryStatus: 'sent',
      timestamp: event.timestamp,
      metadata: notification.metadata,
    };

    this.logRepository.save(entry);
  }

  /**
   * Handle a failed notification delivery — log it as 'failed'.
   */
  private handleNotificationFailed(event: NotificationFailedEvent): void {
    const { notification, reason } = event;
    this.logger.info(
      `Logging failed notification: ${notification.id} — ${reason}`,
    );

    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: notification.id,
      type: notification.type,
      channel: notification.channel,
      recipient: notification.recipient,
      subject: notification.subject,
      body: notification.body,
      priority: notification.priority,
      deliveryStatus: 'failed',
      timestamp: event.timestamp,
      failureReason: reason,
      metadata: notification.metadata,
    };

    this.logRepository.save(entry);
  }

  // ---------------------------------------------------------------------------
  // Query Methods
  // ---------------------------------------------------------------------------

  /**
   * Get all notification log entries.
   */
  getAll(): NotificationLogEntry[] {
    return this.logRepository.findAll();
  }

  /**
   * Get the total count of log entries.
   */
  getCount(): number {
    return this.logRepository.count();
  }

  /**
   * Get a specific log entry by its ID.
   */
  getById(id: string): NotificationLogEntry | undefined {
    return this.logRepository.findById(id);
  }

  /**
   * Get the log entry for a specific notification ID.
   */
  getByNotificationId(notificationId: string): NotificationLogEntry | undefined {
    return this.logRepository.findByNotificationId(notificationId);
  }

  /**
   * Get all log entries for a specific recipient.
   *
   * @param recipient - The recipient identifier to filter by.
   */
  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.logRepository.findByRecipient(recipient);
  }

  /**
   * Get all log entries of a specific notification type.
   *
   * @param type - The notification type to filter by.
   */
  getByType(type: NotificationType): NotificationLogEntry[] {
    return this.logRepository.findByType(type);
  }

  /**
   * Get all log entries for a specific delivery channel.
   *
   * @param channel - The notification channel to filter by.
   */
  getByChannel(channel: NotificationChannel): NotificationLogEntry[] {
    return this.logRepository.findByChannel(channel);
  }

  /**
   * Get all log entries within a date range (inclusive).
   *
   * @param startDate - The start of the date range.
   * @param endDate - The end of the date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.logRepository.findByDateRange(startDate, endDate);
  }

  /**
   * Query notification history with combined filters.
   *
   * All query fields are optional. Omit a field to skip that filter.
   * When multiple fields are provided, all conditions must match (AND logic).
   *
   * @param query - The filter criteria.
   * @returns Matching log entries.
   */
  query(query: NotificationHistoryQuery): NotificationLogEntry[] {
    return this.logRepository.findAll((entry) => {
      if (query.recipient !== undefined && entry.recipient !== query.recipient) {
        return false;
      }
      if (query.type !== undefined && entry.type !== query.type) {
        return false;
      }
      if (query.channel !== undefined && entry.channel !== query.channel) {
        return false;
      }
      if (query.deliveryStatus !== undefined && entry.deliveryStatus !== query.deliveryStatus) {
        return false;
      }
      if (query.startDate !== undefined && entry.timestamp < query.startDate) {
        return false;
      }
      if (query.endDate !== undefined && entry.timestamp > query.endDate) {
        return false;
      }
      return true;
    });
  }

  /**
   * Query notification history with pagination.
   *
   * @param query - The filter criteria.
   * @param page - The page number (1-indexed).
   * @param pageSize - Number of items per page.
   * @returns Paginated results.
   */
  queryPaginated(
    query: NotificationHistoryQuery,
    page: number,
    pageSize: number,
  ): PaginationResult<NotificationLogEntry> {
    const results = this.query(query);
    return paginate(results, page, pageSize);
  }
}

