import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../../src/events/event-types.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let logRepository: NotificationLogRepository;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    logRepository = new NotificationLogRepository(db);

    // NotificationService must be created first so it registers its handlers,
    // then NotificationHistoryService subscribes to the lifecycle events.
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter({ stubMode: true });
    notificationService.registerAdapter(emailAdapter);

    historyService = new NotificationHistoryService(eventBus, logRepository);

    resetNotificationIdCounter();
    resetNotificationLogIdCounter();
  });

  // ---------------------------------------------------------------------------
  // Automatic logging via EventBus integration
  // ---------------------------------------------------------------------------

  describe('automatic logging of sent notifications', () => {
    it('should log a notification when notification:sent is emitted', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.deliveryStatus).toBe('sent');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.type).toBe('welcome');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.subject).toContain('Welcome');
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.id).toBe('nlog-0001');
    });

    it('should log a notification for order:created events', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.deliveryStatus).toBe('sent');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.recipient).toBe('alice@example.com');
    });

    it('should log multiple notifications sequentially', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(2);
      expect(logs[0]?.id).toBe('nlog-0001');
      expect(logs[1]?.id).toBe('nlog-0002');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[1]?.recipient).toBe('bob@example.com');
    });

    it('should capture metadata from notification record', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs[0]?.metadata).toBeDefined();
      expect(logs[0]?.metadata?.['userId']).toBe('user-1');
    });
  });

  describe('automatic logging of failed notifications', () => {
    it('should log a failed notification when no adapter is registered', async () => {
      notificationService.unregisterAdapter('email');

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.deliveryStatus).toBe('failed');
      expect(logs[0]?.failureReason).toContain('No adapter registered');
    });

    it('should log a failed notification when adapter returns failure', async () => {
      const failingAdapter: NotificationAdapter = {
        channel: 'email',
        async send(_payload: NotificationPayload): Promise<NotificationResult> {
          return {
            success: false,
            notificationId: '',
            channel: 'email',
            failureReason: 'SMTP connection refused',
          };
        },
      };
      notificationService.registerAdapter(failingAdapter);

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.deliveryStatus).toBe('failed');
      expect(logs[0]?.failureReason).toBe('SMTP connection refused');
    });
  });

  // ---------------------------------------------------------------------------
  // Query by recipient
  // ---------------------------------------------------------------------------

  describe('getByRecipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const aliceLogs = historyService.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]?.recipient).toBe('alice@example.com');

      const bobLogs = historyService.getByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
      expect(bobLogs[0]?.recipient).toBe('bob@example.com');
    });

    it('should return empty array for unknown recipient', () => {
      const logs = historyService.getByRecipient('nobody@example.com');
      expect(logs).toHaveLength(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Query by type
  // ---------------------------------------------------------------------------

  describe('getByType', () => {
    it('should return logs filtered by notification type', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      const welcomeLogs = historyService.getByType('welcome');
      expect(welcomeLogs).toHaveLength(1);

      const statusUpdateLogs = historyService.getByType('order_status_update');
      expect(statusUpdateLogs).toHaveLength(1);

      const orderConfirmLogs = historyService.getByType('order_confirmation');
      expect(orderConfirmLogs).toHaveLength(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Query by channel
  // ---------------------------------------------------------------------------

  describe('getByChannel', () => {
    it('should return logs filtered by channel', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const emailLogs = historyService.getByChannel('email');
      expect(emailLogs).toHaveLength(1);

      const smsLogs = historyService.getByChannel('sms');
      expect(smsLogs).toHaveLength(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Query by date range
  // ---------------------------------------------------------------------------

  describe('getByDateRange', () => {
    it('should return logs within the specified date range', async () => {
      const now = new Date();
      const pastDate = new Date(now.getTime() - 60_000); // 1 minute ago
      const futureDate = new Date(now.getTime() + 60_000); // 1 minute from now

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: now,
      } satisfies UserCreatedEvent);

      const logsInRange = historyService.getByDateRange(pastDate, futureDate);
      expect(logsInRange).toHaveLength(1);

      // Range that ends before the event timestamp
      const earlyEnd = new Date(now.getTime() - 30_000);
      const logsOutOfRange = historyService.getByDateRange(
        new Date(now.getTime() - 120_000),
        earlyEnd,
      );
      expect(logsOutOfRange).toHaveLength(0);
    });
  });

  // ---------------------------------------------------------------------------
  // Combined query
  // ---------------------------------------------------------------------------

  describe('query', () => {
    beforeEach(async () => {
      // Create multiple notifications of different types
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      await eventBus.emit({
        type: 'user:updated',
        user: {
          id: 'user-1',
          name: 'Alice Updated',
          email: 'alice@example.com',
          role: 'admin',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        changes: ['name', 'role'],
        timestamp: new Date(),
      } satisfies UserUpdatedEvent);

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);
    });

    it('should return all entries when query is empty', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'welcome' });
      expect(results).toHaveLength(2); // Alice + Bob
    });

    it('should filter by recipient AND type', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'welcome',
      });
      expect(results).toHaveLength(1);
    });

    it('should filter by delivery status', () => {
      const results = historyService.query({ deliveryStatus: 'sent' });
      expect(results).toHaveLength(3);

      const failedResults = historyService.query({ deliveryStatus: 'failed' });
      expect(failedResults).toHaveLength(0);
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'email' });
      expect(results).toHaveLength(3);

      const smsResults = historyService.query({ channel: 'sms' });
      expect(smsResults).toHaveLength(0);
    });

    it('should filter by date range', () => {
      const now = new Date();
      const pastDate = new Date(now.getTime() - 60_000);
      const futureDate = new Date(now.getTime() + 60_000);

      const results = historyService.query({
        startDate: pastDate,
        endDate: futureDate,
      });
      expect(results).toHaveLength(3);
    });

    it('should combine multiple filters with AND logic', () => {
      const results = historyService.query({
        recipient: 'bob@example.com',
        type: 'account_updated',
      });
      expect(results).toHaveLength(0); // Bob has no account_updated
    });
  });

  // ---------------------------------------------------------------------------
  // Paginated query
  // ---------------------------------------------------------------------------

  describe('queryPaginated', () => {
    beforeEach(async () => {
      // Create 5 notifications
      for (let i = 1; i <= 5; i++) {
        await eventBus.emit({
          type: 'user:created',
          user: {
            id: `user-${i}`,
            name: `User ${i}`,
            email: `user${i}@example.com`,
            role: 'member',
            createdAt: new Date(),
            updatedAt: new Date(),
          },
          timestamp: new Date(),
        } satisfies UserCreatedEvent);
      }
    });

    it('should return paginated results', () => {
      const page1 = historyService.queryPaginated({}, 1, 2);
      expect(page1.items).toHaveLength(2);
      expect(page1.page).toBe(1);
      expect(page1.pageSize).toBe(2);
      expect(page1.totalItems).toBe(5);
      expect(page1.totalPages).toBe(3);
      expect(page1.hasNext).toBe(true);
      expect(page1.hasPrevious).toBe(false);
    });

    it('should return correct second page', () => {
      const page2 = historyService.queryPaginated({}, 2, 2);
      expect(page2.items).toHaveLength(2);
      expect(page2.page).toBe(2);
      expect(page2.hasNext).toBe(true);
      expect(page2.hasPrevious).toBe(true);
    });

    it('should return correct last page', () => {
      const page3 = historyService.queryPaginated({}, 3, 2);
      expect(page3.items).toHaveLength(1);
      expect(page3.hasNext).toBe(false);
      expect(page3.hasPrevious).toBe(true);
    });

    it('should apply filters before pagination', () => {
      const result = historyService.queryPaginated(
        { recipient: 'user1@example.com' },
        1,
        10,
      );
      expect(result.totalItems).toBe(1);
      expect(result.items).toHaveLength(1);
      expect(result.items[0]?.recipient).toBe('user1@example.com');
    });
  });

  // ---------------------------------------------------------------------------
  // Individual query methods
  // ---------------------------------------------------------------------------

  describe('getCount', () => {
    it('should return 0 when no logs exist', () => {
      expect(historyService.getCount()).toBe(0);
    });

    it('should return correct count after logging', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      expect(historyService.getCount()).toBe(1);
    });
  });

  describe('getById', () => {
    it('should return a log entry by its ID', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const entry = historyService.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry?.id).toBe('nlog-0001');
      expect(entry?.recipient).toBe('alice@example.com');
    });

    it('should return undefined for non-existent ID', () => {
      const entry = historyService.getById('nlog-9999');
      expect(entry).toBeUndefined();
    });
  });

  describe('getByNotificationId', () => {
    it('should return a log entry by its notification ID', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const entry = historyService.getByNotificationId('notif-0001');
      expect(entry).toBeDefined();
      expect(entry?.notificationId).toBe('notif-0001');
    });

    it('should return undefined for non-existent notification ID', () => {
      const entry = historyService.getByNotificationId('notif-9999');
      expect(entry).toBeUndefined();
    });
  });

  // ---------------------------------------------------------------------------
  // Integration: full flow from domain event to history log
  // ---------------------------------------------------------------------------

  describe('end-to-end integration', () => {
    it('should log the full notification lifecycle from order:created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 15 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Verify notification was created in NotificationService
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.status).toBe('sent');

      // Verify history was logged
      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);

      const log = logs[0]!;
      expect(log.notificationId).toBe(notifications[0]?.id);
      expect(log.type).toBe('order_confirmation');
      expect(log.channel).toBe('email');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.deliveryStatus).toBe('sent');
      expect(log.subject).toContain('Order Confirmation');
      expect(log.body).toContain('Widget x3');
      expect(log.body).toContain('$45.00');
      expect(log.priority).toBe('normal');
      expect(log.timestamp).toBeInstanceOf(Date);
      expect(log.failureReason).toBeUndefined();
    });

    it('should log both sent and failed notifications in mixed scenario', async () => {
      // Send a successful notification
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      // Remove the adapter so next notification fails
      notificationService.unregisterAdapter('email');

      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(2);

      const sentLogs = historyService.query({ deliveryStatus: 'sent' });
      expect(sentLogs).toHaveLength(1);
      expect(sentLogs[0]?.recipient).toBe('alice@example.com');

      const failedLogs = historyService.query({ deliveryStatus: 'failed' });
      expect(failedLogs).toHaveLength(1);
      expect(failedLogs[0]?.recipient).toBe('bob@example.com');
      expect(failedLogs[0]?.failureReason).toContain('No adapter registered');
    });

    it('should persist logs in the database via repository', async () => {
      await eventBus.emit({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      // Verify the log is in the repository (database-backed)
      const repoEntry = logRepository.findById('nlog-0001');
      expect(repoEntry).toBeDefined();
      expect(repoEntry?.recipient).toBe('alice@example.com');

      // Also verify count from the repository directly
      expect(logRepository.count()).toBe(1);
    });
  });
});

